package com.interview.incidentrca.service;
import com.interview.incidentrca.dto.RootCauseSuggestionResponse;import com.interview.incidentrca.entity.*;import com.interview.incidentrca.mapper.IncidentMapper;import com.interview.incidentrca.repository.RootCauseSuggestionRepository;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Service;import java.time.Instant;import java.util.*;
@Service @RequiredArgsConstructor public class RootCauseService{private final RootCauseSuggestionRepository repo;private final IncidentMapper mapper;private final AuditService audit;private final CurrentUserService current;
 public List<RootCauseSuggestionResponse> suggest(Incident i){var existing=repo.findByIncidentIdOrderByConfidenceScoreDesc(i.getId());if(existing.isEmpty()){String text=(i.getTitle()+" "+i.getDescription()+" "+i.getServiceComponent().getName()).toLowerCase();List<RootCauseSuggestion> generated=new ArrayList<>();rule(i,text,generated,"Database connection issue",List.of("database","db","sql","connection","timeout"),"Database or connection pool keywords found.");rule(i,text,generated,"Authentication failure",List.of("login","auth","token","jwt","unauthorized","forbidden"),"Authentication-related errors found.");rule(i,text,generated,"Memory usage spike",List.of("memory","heap","oom","cpu","slow"),"Resource pressure keywords found.");rule(i,text,generated,"Deployment regression",List.of("deploy","release","rollback","version","regression"),"Incident looks related to recent release activity.");rule(i,text,generated,"External API failure",List.of("thirdparty","external","gateway","api","502","503"),"Upstream dependency failure indicators found.");rule(i,text,generated,"Network latency",List.of("network","latency","dns","packet","timeout"),"Network latency or timeout indicators found.");if(generated.isEmpty())generated.add(build(i,"General application failure",45,"No strong keyword match; inspect logs, recent changes, metrics and dependency health."));existing=repo.saveAll(generated);}audit.record(current.user(),"ROOT_CAUSE_SUGGESTED","Generated/viewed RCA suggestions for incident #"+i.getId());return existing.stream().map(mapper::toSuggestion).toList();}
 private void rule(Incident i,String text,List<RootCauseSuggestion> out,String category,List<String> keys,String reason){long hits=keys.stream().filter(text::contains).count();if(hits>0)out.add(build(i,category,(int)Math.min(95,50+hits*12),reason));}
 private RootCauseSuggestion build(Incident i,String c,int score,String e){return RootCauseSuggestion.builder().incident(i).category(c).confidenceScore(score).explanation(e).createdAt(Instant.now()).build();}
}
